SELECT '=== backtest_results ===' AS section;
SELECT id, strategy_id, task_id, total_return, sharpe_ratio, max_drawdown, trade_count, win_rate, period_start, period_end FROM backtest_results ORDER BY id DESC LIMIT 5;

SELECT '=== trading_signals \(backtest source\) ===' AS section;
SELECT id, strategy_id, pair, direction, signal_source, confidence_score, entry_price, timeframe, signal_at FROM trading_signals WHERE signal_source = 'backtest' ORDER BY id DESC LIMIT 10;

SELECT '=== trading_signals count ===' AS section;
SELECT signal_source, COUNT\(*\) FROM trading_signals GROUP BY signal_source;

SELECT '=== strategy metrics ===' AS section;
SELECT id, name, trade_count, max_drawdown, sharpe_ratio, win_rate FROM strategies WHERE id = 1;
